from typing import List

def random_subarray(dimensions: List[int]) -> List:
    def generate(dim: List[int]):
        if len(dim) == 1:
            return [random.randint(0, 9) for _ in range(dim[0])]
        return [generate(dim[1:]) for _ in range(dim[0])]

    arr = generate(dimensions)

    intervals = [
        (random.randint(0, d - 1), random.randint(1, d)) for d in dimensions
    ]
    intervals = [(b, e) if b < e else (e - 1, e) for b, e in intervals]

    def slice_arr(a, ints):
        if not ints:
            return a
        b, e = ints[0]
        sliced = a[b:e]
        if len(ints) == 1:
            return sliced
        return [slice_arr(sub, ints[1:]) for sub in sliced]

    return slice_arr(arr, intervals)

