import json
from typing import Callable, Dict, Any, Type


class JsonSerializable:
    """Base class for JSON serializable objects with factory registry support."""
    _factory_registry: Dict[str, Callable[..., "JsonSerializable"]] = {}

    def __init__(self, data: Dict[str, Any] | None = None):
        self.data: Dict[str, Any] = data or {}

    def to_json(self) -> str:
        """Convert the instance data to a JSON string."""
        return json.dumps(self.data)

    @classmethod
    def from_json(cls, json_str: str) -> "JsonSerializable":
        """Create a new instance of the class from a JSON string."""
        data = json.loads(json_str)
        return cls(data)

    @classmethod
    def register_factory(cls, id: str, factory_func: Callable[..., "JsonSerializable"]) -> None:
        """Register a factory function for a given ID."""
        cls._factory_registry[id] = factory_func

    @classmethod
    def create_from_id(cls, id: str, *args, **kwargs) -> "JsonSerializable":
        """Create a new instance using the factory function associated with the given ID."""
        factory = cls._factory_registry.get(id)
        if factory is None:
            raise ValueError(f"No factory registered for ID: {id}")
        return factory(*args, **kwargs)


# Convenience functions that operate on the base class registry
def add_factory(id: str, factory_func: Callable[..., JsonSerializable]) -> None:
    JsonSerializable.register_factory(id, factory_func)


def create_instance(id: str, *args, **kwargs) -> JsonSerializable:
    return JsonSerializable.create_from_id(id, *args, **kwargs)


# Example subclass
class Person(JsonSerializable):
    def __init__(self, name: str, age: int):
        super().__init__({"name": name, "age": age})

    @classmethod
    def from_json(cls, json_str: str) -> "Person":
        data = json.loads(json_str)
        return cls(name=data["name"], age=data["age"])


# Register factory for Person
add_factory("person", lambda name, age: Person(name, age))

# Example usage
if __name__ == "__main__":
    # Create a Person instance via factory
    p = create_instance("person", "Alice", 30)
    print(p.to_json())  # {"name": "Alice", "age": 30}

    # Deserialize from JSON
    json_str = '{"name": "Bob", "age": 25}'
    p2 = Person.from_json(json_str)
    print(p2.data)  # {'name': 'Bob', 'age': 25}

