import tensorflow as tf
import torch

def set_weights_and_save(model, layer_names, weights_dict, output_path, fmt='h5'):
    """
    Set weights for specified layers in a pre-trained model and save the model.

    Parameters
    ----------
    model : tf.keras.Model or torch.nn.Module
        The pre-trained model.
    layer_names : list of str
        Names of layers whose weights should be updated.
    weights_dict : dict
        Mapping from layer name to weight values. For Keras layers the value
        should be a list/tuple of numpy arrays. For PyTorch modules the value
        should be a dict mapping parameter names to torch tensors.
    output_path : str
        Path where the modified model will be saved.
    fmt : str, optional
        Output format. For Keras: 'h5', 'tf', 'pb'. For PyTorch: 'pt'.
    """
    if isinstance(model, tf.keras.Model):
        for name in layer_names:
            if name not in weights_dict:
                raise ValueError(f"No weights provided for layer '{name}'.")
            layer = model.get_layer(name)
            layer.set_weights(weights_dict[name])

        if fmt == 'h5':
            model.save(output_path, save_format='h5')
        elif fmt == 'tf':
            model.save(output_path, save_format='tf')
        elif fmt == 'pb':
            tf.saved_model.save(model, output_path)
        else:
            raise ValueError(f"Unsupported format '{fmt}' for Keras model.")

    elif isinstance(model, torch.nn.Module):
        state_dict = model.state_dict()
        for name in layer_names:
            if name not in weights_dict:
                raise ValueError(f"No weights provided for layer '{name}'.")
            sub_dict = weights_dict[name]
            for param_name, tensor in sub_dict.items():
                full_name = f"{name}.{param_name}"
                if full_name not in state_dict:
                    raise ValueError(f"Parameter '{full_name}' not found in model.")
                state_dict[full_name].copy_(tensor)

        if fmt == 'pt':
            torch.save(state_dict, output_path)
        else:
            raise ValueError(f"Unsupported format '{fmt}' for PyTorch model.")

    else:
        raise TypeError("Unsupported model type. Expected tf.keras.Model or torch.nn.Module.")
