def blocked_ips(ip_ports: dict, block_countries: list) -> dict:
    """
    Return a dictionary of IP addresses and ports that should be blocked.
    If the country code 'cn' is in the block_countries list, all IP/port
    combinations from ip_ports are considered blocked.
    """
    blocked = {}
    if 'cn' not in block_countries:
        return blocked  # nothing to block

    for ip, ports in ip_ports.items():
        if isinstance(ports, (list, tuple)):
            blocked[ip] = list(ports)
        else:
            blocked[ip] = ports
    return blocked
