def batch_iterator(list_of_lists, batch_size, cycles):
    if not list_of_lists:
        raise ValueError("Input list_of_lists must not be empty.")
    lengths = [len(sub) for sub in list_of_lists]
    if len(set(lengths)) != 1:
        raise ValueError("All inner lists must have the same length.")
    n_batches = len(list_of_lists)
    indices = list(range(n_batches))
    for _ in range(cycles):
        random.shuffle(indices)
        indices_iter = iter(indices)
        while True:
            batch_indices = list(itertools.islice(indices_iter, batch_size))
            if not batch_indices:
                break
            batch = [list_of_lists[idx] for idx in batch_indices]
            for t in zip(*batch):
                yield t
