import ast
import types

def validate_code(code_str, func_name, args, reference_func):
    """
    Compile and execute `code_str` in a restricted environment,
    then compare the result of the function `func_name(*args)` with
    the output of `reference_func(*args)`.  Returns True if the
    outputs match, otherwise False.  Any compilation or runtime
    errors also result in False.
    """
    # 1. Syntax check
    try:
        parsed = ast.parse(code_str, mode='exec')
    except SyntaxError:
        return False

    # 2. Compile the code
    try:
        compiled = compile(parsed, '<string>', 'exec')
    except Exception:
        return False

    # 3. Prepare a restricted namespace
    restricted_globals = {"__builtins__": {}}
    local_ns = {}

    # 4. Execute the code
    try:
        exec(compiled, restricted_globals, local_ns)
    except Exception:
        return False

    # 5. Retrieve the function
    func = local_ns.get(func_name)
    if not isinstance(func, types.FunctionType):
        return False

    # 6. Execute the function and compare outputs
    try:
        output = func(*args)
        reference_output = reference_func(*args)
    except Exception:
        return False

    return output == reference_output
