CREATE OR REPLACE FUNCTION demo_cursor_function()
RETURNS void AS $$
DECLARE
    cur CURSOR FOR
        SELECT 1 AS id, 'Alice' AS name
        UNION ALL SELECT 2, 'Bob'
        UNION ALL SELECT 3, 'Charlie';
    rec RECORD;
BEGIN
    CREATE TABLE my_temp_table (id INT, name TEXT);

    OPEN cur;
    LOOP
        FETCH cur INTO rec;
        EXIT WHEN NOT FOUND;
        INSERT INTO my_temp_table (id, name) VALUES (rec.id, rec.name);
    END LOOP;
    CLOSE cur;

    DROP TABLE my_temp_table;
END;
$$ LANGUAGE plpgsql;
