import hashlib

class HashContext:
    def __init__(self, algorithm: str = 'sha256'):
        self._hash = hashlib.new(algorithm)

    def update(self, data: str):
        self._hash.update(data.encode('utf-8'))

    def digest(self) -> str:
        return self._hash.hexdigest()

    def clone(self):
        cloned = HashContext()
        cloned._hash = self._hash.copy()
        return cloned

def compute_hash(data: str, algorithm: str = 'sha256') -> str:
    ctx = HashContext(algorithm)
    ctx.update(data)
    return ctx.digest()

