try:
    import psutil
except ImportError:
    psutil = None


def terminate_process(pid, initial_sleep=0.5, max_sleep=5.0, factor=2.0):
    """
    Gracefully terminate a process by PID.
    Returns:
        0  - if the process was terminated or already exited.
       -1  - if the process is not running.
    """
    # Check if the process is already stopped or failed
    if psutil:
        try:
            proc = psutil.Process(pid)
        except psutil.NoSuchProcess:
            return -1
        except psutil.ZombieProcess:
            return -1
        if not proc.is_running():
            return -1
    else:
        # Fallback check (works on POSIX, may not work on Windows)
        try:
            os.kill(pid, 0)
        except OSError:
            return -1

    # Send termination signal
    try:
        if os.name == "nt":
            # Windows: use taskkill for graceful termination
            subprocess.run(
                ["taskkill", "/PID", str(pid), "/T"],
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                check=False,
            )
        else:
            os.kill(pid, signal.SIGTERM)
    except Exception:
        pass  # Ignore errors when sending the signal

    # Wait for the process to exit, with exponential back‑off
    sleep = initial_sleep
    while True:
        if psutil:
            try:
                if not psutil.Process(pid).is_running():
                    return 0
            except psutil.NoSuchProcess:
                return 0
        else:
            try:
                os.kill(pid, 0)
            except OSError:
                return 0

        if sleep > max_sleep:
            break
        time.sleep(sleep)
        sleep = min(sleep * factor, max_sleep)

    return 0
