import sys
import subprocess
import re
import json
from collections import Counter

def extract_text(pdf_path: str) -> str:
    try:
        result = subprocess.run(
            ["pdftotext", pdf_path, "-"],
            capture_output=True,
            text=True,
            check=True,
        )
    except subprocess.CalledProcessError as e:
        sys.exit(f"Error extracting PDF: {e}")
    except FileNotFoundError:
        sys.exit("pdftotext not found. Install poppler-utils.")
    return result.stdout

def tokenize(text: str) -> list[str]:
    return re.findall(r"\b\w+\b", text.lower())

def bag_of_words(tokens: list[str]) -> dict[str, int]:
    return dict(Counter(tokens))

def main():
    if len(sys.argv) < 2:
        sys.exit("Usage: python script.py input.pdf [output.json]")
    pdf_path = sys.argv[1]
    output_path = sys.argv[2] if len(sys.argv) > 2 else "bag_of_words.json"

    raw_text = extract_text(pdf_path)
    tokens = tokenize(raw_text)
    bow = bag_of_words(tokens)

    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(bow, f, ensure_ascii=False, indent=2)

    print(f"Bag-of-words written to {output_path}")

if __name__ == "__main__":
    main()
