def _deprecation_warning(old_name, new_name, warning_msg, version):
    msg = warning_msg or f"'{old_name}' is deprecated; use '{new_name}' instead."
    if version:
        msg += f" (Deprecated in version {version})"
    warnings.warn(msg, DeprecationWarning, stacklevel=3)

def deprecated_attribute(old_name, new_name, warning_msg=None, version=None):
    def _getter(self):
        _deprecation_warning(old_name, new_name, warning_msg, version)
        return getattr(self, new_name)

    def _setter(self, value):
        _deprecation_warning(old_name, new_name, warning_msg, version)
        setattr(self, new_name, value)

    return property(_getter, _setter)

