#!/usr/bin/env python3
import argparse
import pickle
import sys
from typing import Any, Iterable, List, Tuple, Union

def load_pickle(path: str) -> Any:
    with open(path, "rb") as f:
        return pickle.load(f)

def save_pickle(obj: Any, path: str) -> None:
    with open(path, "wb") as f:
        pickle.dump(obj, f, protocol=pickle.HIGHEST_PROTOCOL)

def linear_interpolate(
    data: Iterable[Tuple[Union[int, float], Union[int, float]]],
    step: Union[int, float],
) -> List[Tuple[Union[int, float], Union[int, float]]]:
    """Perform simple linear interpolation on a list of (x, y) pairs.
    Assumes data is sorted by x. Generates points at regular intervals of `step`.
    """
    points = sorted(data, key=lambda p: p[0])
    if not points:
        return []

    x_vals, y_vals = zip(*points)
    x_min, x_max = x_vals[0], x_vals[-1]
    interpolated = []

    current_x = x_min
    i = 0
    while current_x <= x_max:
        # Find segment containing current_x
        while i < len(points) - 1 and points[i + 1][0] < current_x:
            i += 1
        if i == len(points) - 1:
            y = points[i][1]
        else:
            x0, y0 = points[i]
            x1, y1 = points[i + 1]
            if x1 == x0:
                y = y0
            else:
                t = (current_x - x0) / (x1 - x0)
                y = y0 + t * (y1 - y0)
        interpolated.append((current_x, y))
        current_x += step
    return interpolated

def search_replace(
    data: Any,
    target: Any,
    replacement: Any,
) -> Any:
    """Recursively replace all occurrences of `target` with `replacement` in `data`."""
    if isinstance(data, list):
        return [search_replace(item, target, replacement) for item in data]
    if isinstance(data, tuple):
        return tuple(search_replace(item, target, replacement) for item in data)
    if isinstance(data, dict):
        return {
            search_replace(k, target, replacement): search_replace(v, target, replacement)
            for k, v in data.items()
        }
    if data == target:
        return replacement
    return data

def main() -> None:
    parser = argparse.ArgumentParser(description="Process pickle files.")
    parser.add_argument("--interp-in", help="Input pickle file for interpolation")
    parser.add_argument("--interp-out", help="Output pickle file for interpolation result")
    parser.add_argument("--interp-step", type=float, default=1.0, help="Step size for interpolation")
    parser.add_argument("--search-in", help="Input pickle file for search/replace")
    parser.add_argument("--search-out", help="Output pickle file for search/replace result")
    parser.add_argument("--search-target", help="Target value to replace")
    parser.add_argument("--search-replace", help="Replacement value")
    parser.add_argument("--copy-in", help="Input pickle file to copy unchanged")
    parser.add_argument("--copy-out", help="Output pickle file for copied data")

    args = parser.parse_args()

    # Interpolation
    if args.interp_in and args.interp_out:
        raw_data = load_pickle(args.interp_in)
        if not isinstance(raw_data, list):
            print(f"Interpolation input {args.interp_in} is not a list.", file=sys.stderr)
            sys.exit(1)
        # Expect list of (x, y) tuples
        try:
            interpolated = linear_interpolate(raw_data, args.interp_step)
        except Exception as e:
            print(f"Error during interpolation: {e}", file=sys.stderr)
            sys.exit(1)
        save_pickle(interpolated, args.interp_out)

    # Search and replace
    if args.search_in and args.search_out and args.search_target is not None and args.search_replace is not None:
        raw_data = load_pickle(args.search_in)
        # Convert target and replacement to appropriate types if possible
        try:
            target = eval(args.search_target, {"__builtins__": None})
        except Exception:
            target = args.search_target
        try:
            replacement = eval(args.search_replace, {"__builtins__": None})
        except Exception:
            replacement = args.search_replace
        modified = search_replace(raw_data, target, replacement)
        save_pickle(modified, args.search_out)

    # Copy unchanged
    if args.copy_in and args.copy_out:
        data = load_pickle(args.copy_in)
        save_pickle(data, args.copy_out)

if __name__ == "__main__":
    main()
