CREATE OR REPLACE FUNCTION demo_lock(lock_name text) RETURNS integer AS $$
DECLARE
    rows_inserted integer := 0;
BEGIN
    -- Drop the table if it already exists
    DROP TABLE IF EXISTS demo_tbl;

    -- Create a table with an auto‑incrementing primary key and a unique name column
    CREATE TABLE demo_tbl (
        id   serial PRIMARY KEY,
        name text UNIQUE NOT NULL
    );

    -- Insert two rows with unique names
    INSERT INTO demo_tbl(name) VALUES ('Alice'), ('Bob');
    rows_inserted := rows_inserted + 2;

    -- Attempt to insert a duplicate name without acquiring a lock
    BEGIN
        INSERT INTO demo_tbl(name) VALUES ('Alice');
        rows_inserted := rows_inserted + 1;
    EXCEPTION WHEN unique_violation THEN
        -- Raise an OperationalError (SQLSTATE 40001) to indicate the failure
        RAISE EXCEPTION 'OperationalError: duplicate key value violates unique constraint "demo_tbl_name_key"' USING ERRCODE = '40001';
    END;

    -- Acquire a write lock on the table using an advisory lock
    PERFORM pg_advisory_lock(hashtext(lock_name));

    -- Insert the duplicate name again (this will now succeed because the lock is held)
    INSERT INTO demo_tbl(name) VALUES ('Alice');
    rows_inserted := rows_inserted + 1;

    -- Release the advisory lock
    PERFORM pg_advisory_unlock(hashtext(lock_name));

    RETURN rows_inserted;
END;
$$ LANGUAGE plpgsql;

