import sqlite3

def get_row_counts(db_path, table_names):
    """
    Returns a dictionary mapping each table name to its row count.
    Raises ValueError if any table has zero rows or if the tables have different schemas.
    """
    if not table_names:
        return {}

    conn = sqlite3.connect(db_path)
    try:
        cursor = conn.cursor()
        schemas = {}
        counts = {}

        # Retrieve schema and row count for each table
        for table in table_names:
            cursor.execute(f"PRAGMA table_info({table})")
            schema = cursor.fetchall()
            if not schema:
                raise ValueError(f"Table '{table}' does not exist or has no columns.")
            schemas[table] = schema

            cursor.execute(f"SELECT COUNT(*) FROM {table}")
            count = cursor.fetchone()[0]
            if count == 0:
                raise ValueError(f"Table '{table}' has zero rows.")
            counts[table] = count

        # Compare schemas
        first_schema = next(iter(schemas.values()))
        for tbl, schema in schemas.items():
            if schema != first_schema:
                raise ValueError(f"Schema mismatch detected in table '{tbl}'.")

        return counts
    finally:
        conn.close()
