import sys

def get_remote_ip(url):
    try:
        result = subprocess.run(
            ["curl", "-s", url],
            check=True,
            capture_output=True,
            text=True,
        )
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Command failed with return code {e.returncode}") from e

    output = result.stdout.strip()
    if not output:
        raise RuntimeError("No output received from remote command")

    # Extract an IPv4 address from the output
    match = re.search(r"(\d{1,3}(?:\.\d{1,3}){3})", output)
    if not match:
        raise RuntimeError("Could not find IP address in output")

    ip = match.group(1)

    # Validate each octet is between 0 and 255
    if not all(0 <= int(octet) <= 255 for octet in ip.split(".")):
        raise RuntimeError(f"Invalid IP address format: {ip}")

    return ip

