import subprocess
import sys
from collections import defaultdict

def run_hg_log():
    """Run hg log and return a list of (node, parents, branch) tuples."""
    cmd = ["hg", "log", "--template", "{node}\\n{parents}\\n{branch}\\n"]
    try:
        output = subprocess.check_output(cmd, text=True)
    except subprocess.CalledProcessError as e:
        print(f"Error running hg log: {e}", file=sys.stderr)
        sys.exit(1)
    lines = output.strip().splitlines()
    commits = []
    for i in range(0, len(lines), 3):
        node = lines[i].strip()
        parents_line = lines[i+1].strip()
        parents = parents_line.split() if parents_line else []
        branch = lines[i+2].strip()
        commits.append((node, parents, branch))
    return commits

def build_graph(commits):
    parents = {}
    children = defaultdict(list)
    for node, par_list, _ in commits:
        parents[node] = par_list
        for p in par_list:
            children[p].append(node)
    return parents, children

def find_heads(children, all_nodes):
    heads = set()
    for node in all_nodes:
        if not children[node]:
            heads.add(node)
    return heads

def main():
    commits = run_hg_log()
    if not commits:
        print("No commits found.")
        return
    parents, children = build_graph(commits)
    all_nodes = set(parents.keys())
    heads = find_heads(children, all_nodes)

    sys.setrecursionlimit(max(1000, len(all_nodes) * 2))

    from functools import lru_cache

    @lru_cache(maxsize=None)
    def reachable_heads(node):
        """Return the set of heads reachable from node."""
        if node in heads:
            return {node}
        res = set()
        for child in children.get(node, []):
            res.update(reachable_heads(child))
        return res

    # Output number of branches (heads) at each commit
    for node, _, _ in commits:
        num_branches = len(reachable_heads(node))
        print(f"{node}: {num_branches}")

