import os

CREDENTIALS_FILE = "credentials.json"

def load_credentials():
    if not os.path.exists(CREDENTIALS_FILE):
        return {}
    with open(CREDENTIALS_FILE, "r") as f:
        return json.load(f).get("devices", [])

def find_credentials(ip, devices):
    for dev in devices:
        if dev.get("ip") == ip:
            return dev.get("user"), dev.get("password")
    return None, None

def main():
    ip = input("Enter device IP address: ").strip()
    username = input("Enter username (leave blank to use stored creds): ").strip()
    password = input("Enter password (leave blank to use stored creds): ").strip()
    power_state = input("Enter power state (on/off): ").strip().lower()

    if power_state not in ("on", "off"):
        print("Invalid power state. Must be 'on' or 'off'.")
        return

    devices = load_credentials()
    if not username or not password:
        stored_user, stored_pass = find_credentials(ip, devices)
        if stored_user and stored_pass:
            username = username or stored_user
            password = password or stored_pass
        else:
            print(f"No stored credentials found for {ip}.")
            return

    cmd = [
        "ipmitool",
        "-I", "lanplus",
        "-H", ip,
        "-U", username,
        "-P", password,
        "power",
        power_state
    ]

    print("Executing command:")
    print(" ".join(cmd))

    try:
        result = subprocess.run(cmd, capture_output=True, text=True, check=True)
        print("Command output:")
        print(result.stdout)
    except subprocess.CalledProcessError as e:
        print("Command failed:")
        print(e.stderr)

if __name__ == "__main__":
    main()
