import json
import os
from urllib.parse import urlparse
from typing import Iterable, Iterator, Optional, Dict, Any

# Optional imports for bucket access
try:
    import boto3
    from botocore.exceptions import BotoCoreError, ClientError
except ImportError:
    boto3 = None

try:
    from google.cloud import storage as gcs_storage
    from google.auth.exceptions import GoogleAuthError
except ImportError:
    gcs_storage = None


class InputSource:
    """
    Reads input from a local file or a cloud bucket (S3/Google Cloud Storage).
    Provides an iterator over the file's lines.

    Attributes
    ----------
    source : str
        Path to the file or bucket object. For cloud objects, use
        's3://bucket/key' or 'gs://bucket/key'.
    fail_on_missing : bool
        If True, raise FileNotFoundError when the source does not exist.
        If False, return an empty iterator.
    """

    def __init__(self, source: str, fail_on_missing: bool = True):
        self.source = source
        self.fail_on_missing = fail_on_missing

    def __iter__(self) -> Iterator[str]:
        return self._iter_lines()

    def _iter_lines(self) -> Iterator[str]:
        parsed = urlparse(self.source)
        scheme = parsed.scheme.lower()

        if scheme in ("", "file"):
            return self._iter_local_file(parsed.path)

        if scheme == "s3":
            if not boto3:
                raise RuntimeError("boto3 is required for S3 access")
            return self._iter_s3_object(parsed.netloc, parsed.path.lstrip("/"))

        if scheme == "gs":
            if not gcs_storage:
                raise RuntimeError("google-cloud-storage is required for GCS access")
            return self._iter_gcs_object(parsed.netloc, parsed.path.lstrip("/"))

        raise ValueError(f"Unsupported URI scheme: {scheme}")

    def _iter_local_file(self, path: str) -> Iterator[str]:
        if not os.path.exists(path):
            if self.fail_on_missing:
                raise FileNotFoundError(f"Local file not found: {path}")
            return iter([])

        with open(path, "r", encoding="utf-8") as f:
            for line in f:
                yield line.rstrip("\n")

    def _iter_s3_object(self, bucket: str, key: str) -> Iterator[str]:
        try:
            s3 = boto3.client("s3")
            obj = s3.get_object(Bucket=bucket, Key=key)
            body = obj["Body"]
            for line in body.iter_lines(decode_unicode=True):
                yield line
        except (BotoCoreError, ClientError) as exc:
            if self.fail_on_missing:
                raise FileNotFoundError(f"S3 object not found: s3://{bucket}/{key}") from exc
            return iter([])

    def _iter_gcs_object(self, bucket_name: str, blob_name: str) -> Iterator[str]:
        try:
            client = gcs_storage.Client()
            bucket = client.bucket(bucket_name)
            blob = bucket.blob(blob_name)
            if not blob.exists():
                raise FileNotFoundError
            data = blob.download_as_text(encoding="utf-8")
            for line in data.splitlines():
                yield line
        except (GoogleAuthError, FileNotFoundError) as exc:
            if self.fail_on_missing:
                raise FileNotFoundError(f"GCS object not found: gs://{bucket_name}/{blob_name}") from exc
            return iter([])

    def to_json(self) -> Dict[str, Any]:
        """Return a JSON-serializable representation of the instance."""
        return {
            "source": self.source,
            "fail_on_missing": self.fail_on_missing,
        }

    @classmethod
    def from_json(cls, data: Dict[str, Any]) -> "InputSource":
        """Create an InputSource instance from its JSON representation."""
        source = data.get("source")
        fail_on_missing = data.get("fail_on_missing", True)
        if source is None:
            raise ValueError("JSON data must contain 'source'")
        return cls(source, fail_on_missing)

    def __repr__(self) -> str:
        return f"<InputSource source={self.source!r} fail_on_missing={self.fail_on_missing}>"
