import json
import os
import getpass
import requests

CONFIG_FILE = 'config.json'
AUTH_ENDPOINT = 'https://example.com/api/auth'  # Replace with actual endpoint

def load_config(path):
    if not os.path.exists(path):
        return {}
    with open(path, 'r') as f:
        try:
            return json.load(f)
        except json.JSONDecodeError:
            return {}

def save_config(path, data):
    with open(path, 'w') as f:
        json.dump(data, f, indent=4)

def prompt_for_missing(config):
    if 'username' not in config or not config['username']:
        config['username'] = input('Enter username: ')
    if 'password' not in config or not config['password']:
        config['password'] = getpass.getpass('Enter password: ')
    if 'api_key' not in config or not config['api_key']:
        config['api_key'] = input('Enter API key: ')
    if 'api_secret' not in config or not config['api_secret']:
        config['api_secret'] = getpass.getpass('Enter API secret: ')
    return config

def authenticate(username, password, api_key, api_secret):
    headers = {
        'X-API-Key': api_key,
        'X-API-Secret': api_secret,
        'Content-Type': 'application/json'
    }
    payload = {'username': username, 'password': password}
    try:
        resp = requests.post(AUTH_ENDPOINT, json=payload, headers=headers, timeout=10)
        resp.raise_for_status()
        data = resp.json()
        return data.get('success', False)
    except (requests.RequestException, ValueError):
        return False

def main():
    config = load_config(CONFIG_FILE)
    config = prompt_for_missing(config)
    save_config(CONFIG_FILE, config)

    success = authenticate(
        config['username'],
        config['password'],
        config['api_key'],
        config['api_secret']
    )

    if success:
        print('Authentication successful.')
    else:
        print('Authentication failed.')

if __name__ == '__main__':
    main()
