CREATE OR REPLACE FUNCTION create_triggers_for_each_row()
RETURNS void
LANGUAGE plpgsql
AS $$
DECLARE
    rec RECORD;
    trg_name text;
    trg_func_name text := 'my_trigger_func';
BEGIN
    -- Ensure trigger function exists
    IF NOT EXISTS (
        SELECT 1
        FROM pg_proc
        WHERE proname = trg_func_name
          AND pronamespace = 'public'::regnamespace
    ) THEN
        CREATE OR REPLACE FUNCTION public.my_trigger_func()
        RETURNS trigger
        LANGUAGE plpgsql
        AS $func$
        BEGIN
            RETURN NEW;
        END;
        $func$;
    END IF;

    -- Drop existing triggers with naming convention
    FOR rec IN
        SELECT tgname, tgrelid::regclass AS tablename
        FROM pg_trigger
        WHERE tgname LIKE 'my_trigger_%'
    LOOP
        EXECUTE format('DROP TRIGGER IF EXISTS %I ON %I', rec.tgname, rec.tablename);
    END LOOP;

    -- Create triggers for each table returned by SELECT
    FOR rec IN
        SELECT tablename
        FROM pg_tables
        WHERE schemaname = 'public'
    LOOP
        trg_name := 'my_trigger_' || rec.tablename;
        EXECUTE format(
            'CREATE TRIGGER %I BEFORE INSERT OR UPDATE OR DELETE ON %I
             FOR EACH ROW EXECUTE FUNCTION %I()',
            trg_name,
            rec.tablename,
            trg_func_name
        );
    END LOOP;

    -- Install new language if necessary
    IF NOT EXISTS (
        SELECT 1
        FROM pg_language
        WHERE lanname = 'plpython3u'
    ) THEN
        CREATE LANGUAGE plpython3u;
    END IF;
END;
$$;

