        """
        Return a queryset of events matching the given location and audience.
        """
        return cls.objects.filter(location=location, audience=audience)

    def render_with_password(self, request, password):
        """
        Render the event detail page only if the provided password matches the
        configured EVENT_PASSWORD. Otherwise return a 403 Forbidden response.
        """
        if password == settings.EVENT_PASSWORD:
            return render(request, "event_detail.html", {"event": self})
