import argparse
import sys

class CodeBlockCLI:
    def __init__(self):
        self._lines = []

    def append_line(self, line: str) -> None:
        """Append a single line to the code block."""
        self._lines.append(line.rstrip("\n"))

    def get_code(self) -> str:
        """Return the concatenated code block."""
        return "\n".join(self._lines)

    def run(self, globals_=None, locals_=None) -> None:
        """Print and execute the code block."""
        code = self.get_code()
        print("=== Code Block ===")
        print(code)
        print("=================")
        exec(code, globals_, locals_)

    def clear(self) -> None:
        """Clear all stored lines."""
        self._lines.clear()


def _parse_args():
    parser = argparse.ArgumentParser(description="Execute code blocks.")
    group = parser.add_mutually_exclusive_group(required=True)
    group.add_argument("-c", "--code", help="Code string to execute.")
    group.add_argument("-f", "--file", help="File containing code to execute.")
    return parser.parse_args()


def main():
    args = _parse_args()
    cli = CodeBlockCLI()
    if args.code:
        for line in args.code.splitlines():
            cli.append_line(line)
    else:
        with open(args.file, "r", encoding="utf-8") as f:
            for line in f:
                cli.append_line(line)
    cli.run()


if __name__ == "__main__":
    main()

