    def __init__(self, expectations_file=None, display_width=1024, display_height=768, display_depth=24):
        """
        :param expectations_file: Path to a JSON or YAML file containing test expectations.
        :param display_width: Width of the virtual display.
        :param display_height: Height of the virtual display.
        :param display_depth: Color depth of the virtual display.
        """
        self.expectations_file = expectations_file
        self.expectations = {}
        self.display = None
        self.width = display_width
        self.height = display_height
        self.depth = display_depth

    def _start_virtual_display(self):
        try:
            from pyvirtualdisplay import Display
            self.display = Display(visible=0, size=(self.width, self.height), color_depth=self.depth)
            self.display.start()
        except ImportError:
            # pyvirtualdisplay is not available; proceed without a virtual display
            self.display = None

    def _stop_virtual_display(self):
        if self.display:
            self.display.stop()
            self.display = None

    def load_expectations(self):
        if not self.expectations_file:
            return
        if not os.path.exists(self.expectations_file):
            raise FileNotFoundError(f"Expectations file not found: {self.expectations_file}")
        with open(self.expectations_file, 'r', encoding='utf-8') as f:
            if self.expectations_file.endswith('.json'):
                self.expectations = json.load(f)
            elif self.expectations_file.endswith(('.yaml', '.yml')):
                self.expectations = yaml.safe_load(f)
            else:
                raise ValueError("Unsupported expectations file format. Use .json, .yaml, or .yml")

    def get_expectation(self, test_name):
        """
        Retrieve the expectation for a given test name.
        """
        return self.expectations.get(test_name)

    def __enter__(self):
        self._start_virtual_display()
        self.load_expectations()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self._stop_virtual_display()
