import json

def deserialize_json(s: str, decode_keys: bool = False):
    obj = json.loads(s)
    if not decode_keys:
        return obj

    def convert(o):
        if isinstance(o, dict):
            new_dict = {}
            for k, v in o.items():
                try:
                    new_key = json.loads(k)
                except Exception:
                    new_key = k
                new_dict[new_key] = convert(v)
            return new_dict
        elif isinstance(o, list):
            return [convert(item) for item in o]
        else:
            return o

    return convert(obj)

