def load_and_execute_snippets():
    """Load and execute all .py files in the snippets directory."""
    if not os.path.isdir(SNIPPETS_DIR):
        print(f"Snippets directory '{SNIPPETS_DIR}' not found.", file=sys.stderr)
        return

    for filename in sorted(os.listdir(SNIPPETS_DIR)):
        if filename.endswith(".py"):
            path = os.path.join(SNIPPETS_DIR, filename)
            module_name = os.path.splitext(filename)[0]
            spec = importlib.util.spec_from_file_location(module_name, path)
            if spec and spec.loader:
                module = importlib.util.module_from_spec(spec)
                try:
                    spec.loader.exec_module(module)
                    print(f"Executed snippet: {filename}")
                except Exception as exc:
                    print(f"Error executing {filename}: {exc}", file=sys.stderr)

def development_code():
    """Example development code that runs when DEV_MODE is True."""
