import yaml

def update_yaml_config(path, changes):
    """
    Load a YAML configuration file, apply changes, and save it back.
    Parameters:
        path (str): Path to the YAML file.
        changes (dict): Dictionary of key-value pairs to update in the config.
    Returns:
        dict: Updated configuration.
    """
    try:
        with open(path, 'r', encoding='utf-8') as f:
            config = yaml.safe_load(f) or {}
    except FileNotFoundError:
        config = {}
    except (OSError, yaml.YAMLError) as e:
        raise RuntimeError(f"Failed to read YAML file '{path}': {e}")

    if not isinstance(config, dict):
        raise ValueError(f"YAML content is not a mapping: {config}")

    config.update(changes)

    try:
        with open(path, 'w', encoding='utf-8') as f:
            yaml.safe_dump(config, f, default_flow_style=False, sort_keys=False)
    except (OSError, yaml.YAMLError) as e:
        raise RuntimeError(f"Failed to write YAML file '{path}': {e}")

    return config

