import os

def get_current_date():
    return os.popen("date +%Y%m%d").read().strip()

def get_previous_date(days_passed):
    cmd = f"date -d '{days_passed} days ago' +%Y%m%d"
    return os.popen(cmd).read().strip()

def get_last_entry(file_path):
    with open(file_path, 'r') as f:
        lines = f.readlines()
    for line in reversed(lines):
        line = line.strip()
        if line:
            return line
    return None

def parse_yyyymmdd(entry):
    year = int(entry[:4])
    month = int(entry[4:6])
    day = int(entry[6:8])
    return year, month, day

# Example usage
if __name__ == "__main__":
    days_passed = int(input("Enter number of days passed: "))
    current_date = get_current_date()
    previous_date = get_previous_date(days_passed)

