    print("Previous date:", previous_date)

    file_path = "data.txt"
    last_entry = get_last_entry(file_path)
    if last_entry:
        y, m, d = parse_yyyymmdd(last_entry)
        print("Last entry year:", y)
        print("Last entry month:", m)
        print("Last entry day:", d)
    else:
        print("No last entry found.")

