public class AntlrRunner {
    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AntlrRunner <output-directory> <grammar-file> [options...]");
            System.exit(1);
        }

        String outputDir = args[0];
        String grammarFile = args[1];
        List<String> options = new ArrayList<>();
        if (args.length > 2) {
            options.addAll(Arrays.asList(args).subList(2, args.length));
        }

        File dir = new File(outputDir);
        if (!dir.exists() || !dir.isDirectory()) {
            System.err.println("Error: Output directory does not exist or is not a directory: " + outputDir);
            System.exit(1);
        }

        File file = new File(grammarFile);
        if (!file.exists() || !file.isFile()) {
            System.err.println("Error: Grammar file does not exist: " + grammarFile);
            System.exit(1);
        }

        File antlrJar = new File("antlr-4.13.1-complete.jar");
        if (!antlrJar.exists() || !antlrJar.isFile()) {
            System.err.println("Error: ANTLR jar not found: " + antlrJar.getAbsolutePath());
            System.err.println("Please place antlr-4.13.1-complete.jar in the current directory.");
            System.exit(1);
        }

        List<String> command = new ArrayList<>();
        command.add("java");
        command.add("-jar");
        command.add(antlrJar.getAbsolutePath());
        command.add("-o");
        command.add(dir.getAbsolutePath());
        command.add(file.getAbsolutePath());
        command.addAll(options);

        ProcessBuilder pb = new ProcessBuilder(command);
        pb.redirectErrorStream(true);

        try {
            Process process = pb.start();

            try (BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    System.out.println(line);
                }
            }

            int exitCode = process.waitFor();
            if (exitCode != 0) {
                System.err.println("ANTLR tool exited with code " + exitCode + ". Check the output above for details.");
                System.exit(exitCode);
            }
        } catch (IOException e) {
            System.err.println("I/O error while running ANTLR: " + e.getMessage());
            System.exit(1);
        } catch (InterruptedException e) {
            System.err.println("Process was interrupted: " + e.getMessage());
            Thread.currentThread().interrupt();
            System.exit(1);
        }
    }
}

