import requests

def update_asset_type(base_url, asset_type_id, updated_data, token=None):
    url = f"{base_url.rstrip('/')}/asset-types/{asset_type_id}"
    headers = {"Content-Type": "application/json"}
    if token:
        headers["Authorization"] = f"Bearer {token}"
    resp = requests.put(url, json=updated_data, headers=headers)
    try:
        resp.raise_for_status()
    except requests.HTTPError as e:
        raise RuntimeError(f"Failed to update asset type: {e}") from e
    data = resp.json()
    message = data.get("message", "")
    if "success" not in message.lower():
        raise RuntimeError(f"Update not successful: {message}")
    return data
